VALUES
  ('social-worker-moex-01621', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體動力學的定義，下列何者錯誤？', '["團體動力是用來描述在團體中任何時間所發生的事情，主要是為成員所覺察到的一切情況", "團體動力學被描述成一種研究的領域，其使用科學的方法來確定團體為何產生如此般的行為", "團體動力學是一種有關團體行為的基本知識，這種知識是由過去的研究所累積而成的", "團體動力學研究的範圍應該是團體的任何行為，包括：團體的組成、互動、衝突、溝通、規範、 分化、整合、凝聚力、權力、領導、發展等"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01622', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體動力的面向，下列何者錯誤？', '["結構", "歷程", "想像力", "改變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01623', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何項團體成員的行為特徵，比較容易出現在團體的結束階段？', '["因為與其他成員理念不合，價值觀不一致而憤怒暴走", "感覺領導者偏袒不公開始杯葛挑釁", "儘管過去都表現出穩定進步，成員可能出現悲傷退化的現象", "成員顯得畢恭畢敬，親切有禮"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01624', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '領導者如何因應成員阻礙團體發展的行為？①他只是希望引人注意，應該忽視這些行為，自然會', '["以其人之道還治其人之身，讓他了解被嘲諷打斷的感受", "了解他這樣做的 需求，有無文化的因素", "引導其他成員分享因標的成員的阻礙所帶來的影響", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01625', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '某位團體成員說：「接下來的連假，我一方面想和男友出國，另方面又覺得應該回家看阿公」， 下列何項是團體領導者最適當的同理心回應', '["你想去那裡？我也想到日本玩耶", "這次活動是男友約的還是你約的", "你的阿公有怎樣嗎？如果換一天回去不行嗎", "好像一邊是你想要出國玩，一邊是你應該去看阿公，這兩個選項讓你陷入天人交戰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01626', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關角色扮演的知識和概念何者正確？①Lewin是心理劇、社會劇最重要的創始人  ②心理劇是', '["社會劇可增加社會角色和社會問題的理解", "演出受霸凌者心聲的教育 短劇演員，其自我揭露最深", "僅", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01627', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社區的意涵，下列何者錯誤？', '["是相互照顧的網絡", "是指利害與共或居住同一個地方的一群人", "基本上是一個沒有地理界限的社會體系，或是一套服務居民的次體系", "是一個影響社會政策的基地"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01628', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不屬於社會睦鄰運動對社區所做的貢獻？', '["以社區為對象，工作者與工作對象相親相愛", "工作內容隨社區的需要而發展", "配合與聯繫社會相關機關，發掘與運用社會資源", "所推動工作僅限於貧民的濟助問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01629', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關臺灣社區發展的歷史發展，下列何者錯誤？', '["社區發展的概念萌芽於1955年推動「基層民生建設」", "1965年行政院頒布「民生主義現階段社會政策」，將社區發展列為社會福利重要項目之一", "社區發展組織逐漸成型，並獨立於村里之外，成為政府推動社區發展的準行政組織", "1990 年代起臺灣各類社會運動風起雲湧，社區總體營造與福利社區化的推動，形成社區發展 雙元併行的發展"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01630', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者屬於Rothman（1968）社會計畫模式？', '["以大型的科層組織，引導變遷的過程，並設計各種計畫與政策", "以大型教育方案，激勵其自立，協助改善社區居民生活", "將劣勢被壓迫一群人，組織起來，爭取權益", "重視社區組織之有效利用，避免服務之重疊和資源的缺乏"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "f8b10df23095", "answer_pdf_sha1": "f894a3302211", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
